// === FACIS Weather subflow physics ============================================
// Mirrors src/simulators/weather/{simulator,temperature,wind,irradiance}.py
// Determinism: seedrandom.alea seeded via SHA-256(base_seed:entity_id:tag:ts_ms)
// Keep tests/flows/weather.spec.js in sync.

const DEFAULT_CFG = {
    latitude: 52.52,
    longitude: 13.4,
    base_temperature_summer_c: 22,
    base_temperature_winter_c: 0,
    daily_temp_amplitude_c: 8,
    temperature_variance_c: 1.5,
    base_humidity_percent: 65,
    humidity_variance_percent: 8,
    base_wind_speed_ms: 4.0,
    wind_variance_ms: 1.5,
    prevailing_wind_direction_deg: 270,
    wind_direction_variance_deg: 30,
    base_cloud_cover_percent: 40,
    cloud_variance_percent: 15,
    max_clear_sky_ghi_w_m2: 1000
};

function makeRng(baseSeed, entityId, tag, tsMs) {
    const key = String(baseSeed) + ':' + String(entityId) + ':' + String(tag) + ':' + String(tsMs);
    const seedHex = crypto.createHash('sha256').update(key).digest('hex').slice(0, 16);
    return seedrandom.alea(seedHex);
}

function normal(rng, mean, stddev) {
    let u = 0; let v = 0;
    while (u === 0) u = rng();
    while (v === 0) v = rng();
    const z = Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
    return mean + stddev * z;
}

function uniform(rng, min, max) {
    return min + (max - min) * rng();
}

function dayOfYear(d) {
    const start = Date.UTC(d.getUTCFullYear(), 0, 0);
    const diff = d.getTime() - start;
    return Math.floor(diff / 86400000);
}

function seasonalFactor(date) {
    const doy = dayOfYear(date);
    const angle = 2 * Math.PI * (doy - 182) / 365;
    return Math.cos(angle);
}

function diurnalFactor(date) {
    const hour = date.getUTCHours() + date.getUTCMinutes() / 60;
    const angle = 2 * Math.PI * (hour - 15) / 24;
    return Math.cos(angle);
}

function diurnalWindFactor(date) {
    const hour = date.getUTCHours() + date.getUTCMinutes() / 60;
    const angle = 2 * Math.PI * (hour - 14) / 24;
    const f = 1.0 - 0.4 * Math.cos(angle);
    return Math.max(0.6, Math.min(1.4, f));
}

function calculateTemperature(date, cfg, rng) {
    const seasonal = seasonalFactor(date);
    const seasonalMid = (cfg.base_temperature_summer_c + cfg.base_temperature_winter_c) / 2;
    const seasonalAmp = (cfg.base_temperature_summer_c - cfg.base_temperature_winter_c) / 2;
    const seasonalTemp = seasonalMid + seasonalAmp * seasonal;
    const effAmp = cfg.daily_temp_amplitude_c * (0.6 + 0.4 * (seasonal + 1) / 2);
    const diurnal = diurnalFactor(date);
    let t = seasonalTemp + effAmp * diurnal;
    if (cfg.temperature_variance_c > 0) {
        t += normal(rng, 0, cfg.temperature_variance_c);
    }
    return t;
}

function calculateHumidity(temperatureC, cfg, rng) {
    const tempEffect = Math.max(0, temperatureC - 15);
    let h = cfg.base_humidity_percent - tempEffect;
    if (cfg.humidity_variance_percent > 0) {
        h += normal(rng, 0, cfg.humidity_variance_percent);
    }
    return Math.max(20, Math.min(95, h));
}

function calculateWindSpeed(date, cfg, rng) {
    const f = diurnalWindFactor(date);
    let s = cfg.base_wind_speed_ms * f;
    if (cfg.wind_variance_ms > 0) {
        s += normal(rng, 0, cfg.wind_variance_ms);
    }
    return Math.max(0, s);
}

function calculateWindDirection(cfg, rng) {
    let d = cfg.prevailing_wind_direction_deg;
    if (cfg.wind_direction_variance_deg > 0) {
        d += normal(rng, 0, cfg.wind_direction_variance_deg);
    }
    d = d % 360;
    if (d < 0) d += 360;
    return d;
}

function calculateCloudCover(date, cfg, rng) {
    const hour = date.getUTCHours() + date.getUTCMinutes() / 60;
    const angle = 2 * Math.PI * (hour - 15) / 24;
    const diurnalVar = -0.15 * Math.cos(angle);
    let cover = cfg.base_cloud_cover_percent * (1 + diurnalVar);
    if (cfg.cloud_variance_percent > 0) {
        cover += normal(rng, 0, cfg.cloud_variance_percent);
    }
    return Math.max(0, Math.min(100, cover));
}

function solarPosition(date, latitude, longitude) {
    const doy = dayOfYear(date);
    const hourUtc = date.getUTCHours() + date.getUTCMinutes() / 60 + date.getUTCSeconds() / 3600;
    const declination = (23.45 * Math.PI / 180) * Math.sin(2 * Math.PI * (284 + doy) / 365);
    const b = 2 * Math.PI * (doy - 81) / 365;
    const eot = 9.87 * Math.sin(2 * b) - 7.53 * Math.cos(b) - 1.5 * Math.sin(b);
    const timeOffset = 4 * longitude;
    const solarTime = hourUtc * 60 + timeOffset + eot;
    const hourAngleDeg = (solarTime / 4.0) - 180;
    const hourAngle = hourAngleDeg * Math.PI / 180;
    const lat = latitude * Math.PI / 180;
    const sinAlt = Math.sin(lat) * Math.sin(declination) +
        Math.cos(lat) * Math.cos(declination) * Math.cos(hourAngle);
    const altRad = Math.asin(Math.max(-1, Math.min(1, sinAlt)));
    const altDeg = altRad * 180 / Math.PI;
    let azDeg;
    const cosAz = (Math.sin(declination) - Math.sin(lat) * Math.sin(altRad)) /
        (Math.cos(lat) * Math.cos(altRad) + 1e-10);
    const cosAzClamped = Math.max(-1, Math.min(1, cosAz));
    if (hourAngleDeg < 0) {
        azDeg = Math.acos(cosAzClamped) * 180 / Math.PI;
    } else {
        azDeg = 360 - Math.acos(cosAzClamped) * 180 / Math.PI;
    }
    return { altitude_deg: Math.max(0, altDeg), azimuth_deg: azDeg, is_daylight: altDeg > 0 };
}

function clearSkyGhi(altitudeDeg, maxGhi) {
    if (altitudeDeg <= 0) return 0;
    const altRad = altitudeDeg * Math.PI / 180;
    const airMass = 1.0 / Math.max(Math.sin(altRad), 0.05);
    const transmission = Math.pow(0.7, Math.pow(airMass, 0.678));
    return Math.max(0, maxGhi * Math.sin(altRad) * transmission);
}

function applyCloudFactor(clearSky, cloudPercent, rng) {
    if (clearSky <= 0) return 0;
    let f = 1.0 - 0.5 * (cloudPercent / 100.0);
    f = Math.max(0.3, Math.min(1.0, f + uniform(rng, -0.05, 0.05)));
    return clearSky * f;
}

function splitGhi(ghi, altitudeDeg, cloudPercent) {
    if (ghi <= 0 || altitudeDeg <= 0) return { ghi_w_m2: 0, dni_w_m2: 0, dhi_w_m2: 0 };
    const altRad = altitudeDeg * Math.PI / 180;
    const kt = 1.0 - 0.7 * (cloudPercent / 100.0);
    let diffuseFraction;
    if (kt <= 0.22) {
        diffuseFraction = 1.0 - 0.09 * kt;
    } else if (kt <= 0.80) {
        diffuseFraction = 0.9511 - 0.1604 * kt + 4.388 * kt * kt - 16.638 * Math.pow(kt, 3) + 12.336 * Math.pow(kt, 4);
    } else {
        diffuseFraction = 0.165;
    }
    const dhi = ghi * diffuseFraction;
    const directHorizontal = ghi - dhi;
    const dni = directHorizontal / Math.max(Math.sin(altRad), 0.05);
    return {
        ghi_w_m2: Math.max(0, ghi),
        dni_w_m2: Math.max(0, Math.min(dni, 1200)),
        dhi_w_m2: Math.max(0, dhi)
    };
}

function generateWeather(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'weather-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const siteId = payload.site_id || '';
    const cfg = Object.assign({}, DEFAULT_CFG, payload.config || {});
    const date = new Date(isoTs);

    const cloudRng = makeRng(baseSeed, entityId, 'cloud', tsMs);
    const tempRng = makeRng(baseSeed, entityId, 'temp', tsMs);
    const humRng = makeRng(baseSeed, entityId, 'hum', tsMs);
    const windSRng = makeRng(baseSeed, entityId, 'winds', tsMs);
    const windDRng = makeRng(baseSeed, entityId, 'windd', tsMs);
    const irrRng = makeRng(baseSeed, entityId, 'irr', tsMs);

    const cloudCover = calculateCloudCover(date, cfg, cloudRng);
    const temperature = calculateTemperature(date, cfg, tempRng);
    const humidity = calculateHumidity(temperature, cfg, humRng);
    const windSpeed = calculateWindSpeed(date, cfg, windSRng);
    const windDirection = calculateWindDirection(cfg, windDRng);

    const sun = solarPosition(date, cfg.latitude, cfg.longitude);
    let irradiance = { ghi_w_m2: 0, dni_w_m2: 0, dhi_w_m2: 0 };
    if (sun.is_daylight) {
        const clearSky = clearSkyGhi(sun.altitude_deg, cfg.max_clear_sky_ghi_w_m2);
        const adjustedGhi = applyCloudFactor(clearSky, cloudCover, irrRng);
        irradiance = splitGhi(adjustedGhi, sun.altitude_deg, cloudCover);
    }

    return {
        site_id: siteId,
        timestamp: isoTs,
        location: { latitude: cfg.latitude, longitude: cfg.longitude },
        conditions: {
            temperature_c: temperature,
            humidity_percent: humidity,
            wind_speed_ms: windSpeed,
            wind_direction_deg: windDirection,
            cloud_cover_percent: cloudCover,
            ghi_w_m2: irradiance.ghi_w_m2,
            dni_w_m2: irradiance.dni_w_m2,
            dhi_w_m2: irradiance.dhi_w_m2
        }
    };
}

msg.payload = generateWeather(msg.payload || {});
return msg;
